Filter Establishments by Locais-Nova G0 Group

data &lt;-
  data |&gt;
  mutate(primary_cnae = primary_cnae |&gt; str_pad(7, pad = "0")) |&gt;
  inner_join(
    y = locais_nova_lookup_data,
    by = join_by(primary_cnae == cnae, federal_unit)
  ) |&gt;
  rename(
    locais_nova_g0 = g0,
    locais_nova_g1_g2 = g1_g2,
    locais_nova_g3 = g3,
    locais_nova_g4 = g4
